{"content":"     1	/// Deterministic PRNG (SplitMix64). The ONLY source of randomness in generation and
     2	/// non-physics animation, so one seed reproduces a universe exactly.
     3	/// Spec: §5, §7e — no wall-clock, no unseeded randomness.
     4	struct SeededRandom: RandomNumberGenerator {
     5	    private var state: UInt64
     6	    init(seed: UInt64) { state = seed }
     7	
     8	    mutating func next() -> UInt64 {
     9	        state &+= 0x9E37_79B9_7F4A_7C15
    10	        var z = state
    11	        z = (z ^ (z >> 30)) &* 0xBF58_476D_1CE4_E5B9
    12	        z = (z ^ (z >> 27)) &* 0x94D0_49BB_1331_11EB
    13	        return z ^ (z >> 31)
    14	    }
    15	
    16	    /// Deterministic sub-stream for a named subsystem (stars, nebula, asteroids…).
    17	    func stream(_ salt: UInt64) -> SeededRandom { SeededRandom(seed: state ^ salt) }
    18	
    19	    /// Convenience: a Float in [0, 1).
    20	    mutating func unit() -> Float { Float(next() >> 40) / Float(1 << 24) }
    21	}
